import { Fragment } from 'react';

import type { SeriesActions } from '../../../../types/series-actions-template.js';
import { ChartSeriesAction } from '../../../series-action/ChartSeriesAction.js';
import { useSeriesActions } from '../../../series-action/ChartSeriesActionContext.js';
import { LegendItem } from '../types/legend.js';

/**
 * Return the series action template with the original series entity
 */
export function useLegendSeriesActions<T>(
  series: T[],
  getId: (series: T) => string,
): SeriesActions<LegendItem> {
  const { chartSeriesActions } = useSeriesActions();

  return (item?: LegendItem) => {
    const actionSeries = series.find((s) => getId(s) === item?.id);
    if (actionSeries) {
      const actions = chartSeriesActions?.(actionSeries);
      if (actions) {
        if (
          actions instanceof Promise ||
          actions.type === ChartSeriesAction ||
          actions.type === Fragment
        ) {
          return actions;
        } else {
          throw new Error('Invalid type passed for ChartSeriesActions!');
        }
      }
    }
  };
}
